const { exec } = require('child_process');
const path = require('path');

module.exports = async function (context, req) {
    context.log('JavaScript HTTP trigger function processed a request.');

    const inputFilename = req.body.inputFilename;
    const outputFormat = req.body.outputFormat;

    if (!inputFilename || !outputFormat) {
        context.res = {
            status: 400,
            body: "Input filename and output format are required."
        };
        return;
    }

    const inputFilePath = path.join(__dirname, 'documents', inputFilename);
    const outputFilePath = path.join(__dirname, 'converted', `${path.basename(inputFilename, path.extname(inputFilename))}.${outputFormat}`);

    const command = `libreoffice --headless --convert-to ${outputFormat} --outdir ${path.dirname(outputFilePath)} ${inputFilePath}`;

    exec(command, (error, stdout, stderr) => {
        if (error) {
            context.log.error(`Error: ${stderr}`);
            context.res = {
                status: 500,
                body: `Failed to convert document. Error: ${stderr}`
            };
            return;
        }

        context.log(`Document converted successfully: ${stdout}`);
        context.res = {
            status: 200,
            body: `Document converted successfully. Output file path: ${outputFilePath}`
        };
    });
};